# ----------------------------
# TOTP utilities
# ----------------------------
def _b32decode_nopad(s: str) -> bytes:
    s = s.strip().replace(" ", "").upper()
    pad = (-len(s)) % 8
    s_padded = s + ("=" * pad)
    return base64.b32decode(s_padded, casefold=True)

def totp_now(secret_b32: str, step: int = 30, digits: int = 6, algo=hashlib.sha1, t: int | None = None) -> str:
    if t is None:
        t = int(time.time())
    counter = int(t // step)
    key = _b32decode_nopad(secret_b32)
    msg = struct.pack(">Q", counter)
    digest = hmac.new(key, msg, algo).digest()
    offset = digest[-1] & 0x0F
    code_int = struct.unpack(">I", digest[offset:offset + 4])[0] & 0x7FFFFFFF
    code = code_int % (10 ** digits)
    return str(code).zfill(digits)

def verify_totp(secret_b32: str, code: str, window: int = 1, step: int = 30, digits: int = 6) -> bool:
    code = (code or "").strip()
    if not code.isdigit() or len(code) != digits:
        return False
    now = int(time.time())
    for w in range(-window, window + 1):
        t = now + (w * step)
        if hmac.compare_digest(totp_now(secret_b32, step=step, digits=digits, t=t), code):
            return True
    return False

