# ----------------------------
# Auth helpers
# ----------------------------
def get_user(username: str):
    if not username:
        return None
    return USERS.get(username)

def login_user(username: str):
    session["user"] = username
    session["authed"] = True
    session.pop("mfa_pending_user", None)
    session.pop("mfa_pending_iat", None)

def logout_user():
    session.clear()

def current_user():
    u = session.get("user")
    if not u:
        return None
    return get_user(u)

def require_web_login():
    if not session.get("authed") or not session.get("user"):
        return redirect(url_for("login", next=request.path))
    return None

