@app.route("/login", methods=["GET", "POST"])
def login():
    if request.method == "GET":
        return render_template_string(LOGIN_TMPL, error=None)

    username = (request.form.get("username") or "").strip()
    password = request.form.get("password") or ""
    user = get_user(username)
    if not user or not check_password_hash(user["password_hash"], password):
        return render_template_string(LOGIN_TMPL, error="Invalid username or password"), 401

    if user.get("mfa_enabled"):
        session["mfa_pending_user"] = user["username"]
        session["mfa_pending_iat"] = int(time.time())
        session.pop("user", None)
        session.pop("authed", None)
        return redirect(url_for("mfa"))

    login_user(user["username"])
    next_url = request.args.get("next") or url_for("home")
    return redirect(next_url)

@app.route("/mfa", methods=["GET", "POST"])
def mfa():
    pending_user = session.get("mfa_pending_user")
    if not pending_user:
        return redirect(url_for("login"))

    user = get_user(pending_user)
    if not user:
        session.pop("mfa_pending_user", None)
        session.pop("mfa_pending_iat", None)
        return redirect(url_for("login"))

    if request.method == "GET":
        return render_template_string(OTP_TMPL, error=None)

    otp = request.form.get("otp") or ""
    secret_b32 = user.get("mfa_secret_b32")
    if not secret_b32 or not verify_totp(secret_b32, otp):
        return render_template_string(OTP_TMPL, error="Invalid OTP"), 401

    login_user(user["username"])
    next_url = request.args.get("next") or url_for("home")
    return redirect(next_url)

@app.route("/")
def home():
    r = require_web_login()
    if r:
        return r
    user = current_user()
    return render_template_string(HOME_TMPL, username=user["username"], mfa_enabled=bool(user.get("mfa_enabled")))

@app.route("/logout")
def logout():
    logout_user()
    return redirect(url_for("login"))

