def _json_error(message: str, status: int):
    return jsonify({"ok": False, "error": message}), status

def _issue_api_token(username: str) -> str:
    token = secrets.token_urlsafe(32)
    API_TOKENS[token] = {"username": username, "iat": int(time.time())}
    return token

def _api_auth_username_from_token():
    auth = request.headers.get("Authorization") or ""
    if auth.lower().startswith("bearer "):
        token = auth.split(None, 1)[1].strip()
        rec = API_TOKENS.get(token)
        if rec:
            return rec["username"]
    return None

@app.route("/api/login", methods=["POST"])
def api_login():
    data = request.get_json(silent=True) or {}
    username = (data.get("username") or "").strip()
    password = data.get("password") or ""
    otp = (data.get("otp") or "").strip()

    user = get_user(username)
    if not user or not check_password_hash(user["password_hash"], password):
        return _json_error("Invalid username or password", 401)

    if user.get("mfa_enabled"):
        if not otp:
            return jsonify({"ok": False, "mfa_required": True, "error": "OTP required"}), 401
        secret_b32 = user.get("mfa_secret_b32")
        if not secret_b32 or not verify_totp(secret_b32, otp):
            return _json_error("Invalid OTP", 401)

    token = _issue_api_token(user["username"])
    return jsonify({"ok": True, "token": token, "mfa_required": False})

@app.route("/api/direct-login", methods=["POST"])
def api_direct_login():
    data = request.get_json(silent=True) or {}
    username = (data.get("username") or "").strip()
    password = data.get("password") or ""

    user = get_user(username)
    if not user or not check_password_hash(user["password_hash"], password):
        return _json_error("Invalid username or password", 401)

    # Explicitly skip MFA checks here
    token = _issue_api_token(user["username"])
    return jsonify({"ok": True, "token": token, "mfa_skipped": True})

@app.route("/api/me", methods=["GET"])
def api_me():
    username = _api_auth_username_from_token()
    if not username:
        return _json_error("Unauthorized", 401)
    user = get_user(username)
    if not user:
        return _json_error("Unauthorized", 401)
    return jsonify({
        "ok": True,
        "user": {
            "id": user["id"],
            "username": user["username"],
            "mfa_enabled": bool(user.get("mfa_enabled")),
        }
    })

